import time
import os
import pickle
from flask import Flask, request
from werkzeug.contrib.cache import SimpleCache

cache = SimpleCache()
app = Flask(__name__)

# Method for caching API response with expiration
def cache_response(response_data, key, timeout=300):
    timestamp = time.time()
    data_to_cache = {
        'timestamp': timestamp,
        'data': response_data
    }
    with open('cache/' + key + '.pkl', 'wb') as f:
        pickle.dump(data_to_cache, f, pickle.HIGHEST_PROTOCOL)
    cache.set(key, data_to_cache, timeout)

# Method for getting cached API response
def get_cached_response(key):
    if cache.get(key):
        return cache.get(key)['data']
    else:
        if os.path.exists('cache/' + key + '.pkl'):
            with open('cache/' + key + '.pkl', 'rb') as f:
                data = pickle.load(f)
                timestamp = data['timestamp']
                if time.time() - timestamp < 300:  # if not expired
                    cache.set(key, data, 300 - (time.time() - timestamp))
                    return data['data']
                
    return None

# Demo route
@app.route('/')
def index():
    response_key = 'expensive_api_response'
    cached_response = get_cached_response(response_key)
    
    if cached_response:
        response_data = cached_response
    else:
        # Get response from expensive API
        response_data = {'data': 'Expensive API Response'}
        # Cache the response
        cache_response(response_data, response_key, 300)
        
    return response_data